import { useLocation, useNavigate } from "react-router-dom"
import CustomMemberModal from "../components/ProfessionalMemberCard"
import BusinessMemberInfo from "../components/BusinessMemberInfo"

const MemberCardPage = () => {
  const { state } = useLocation()
  const navigate = useNavigate()
  const memberData = state?.memberData

  if (!memberData) return navigate("/")

  return memberData.MemberType === "Doanh nghiệp" ? (
    <BusinessMemberInfo memberData={memberData} />
  ) : (
    <CustomMemberModal memberData={memberData} />
  )
}

export default MemberCardPage
